(2998, 488, 'header', 'Light up the Surprise for Your Gender Reveal'),
(2999, 488, '_header', 'field_664b0f798280d'),
(3000, 488, 'banner_content', '<p style=\"text-align: center;\">Planning a gender reveal party? Make the big announcement truly unforgettable with our Gender Reveal Fireworks. Find dazzling fireworks in both blue and pink hues, perfect for creating a magical moment you\'ll cherish forever.</p>'),
(3001, 488, '_banner_content', 'field_6655851f19ec8'),
(3002, 489, 'header', '500g Cakes for Epic Celebrations'),
(3003, 489, '_header', 'field_664b0f798280d'),
(3004, 489, 'banner_content', '<p style=\"text-align: center;\">Ignite unforgettable memories with our showstopping 500-gram cakes! Offering a dazzling finale of color, sound, and effects, these powerful fireworks are the perfect way to elevate your celebration to the next level.</p>'),
(3005, 489, '_banner_content', 'field_6655851f19ec8'),
(3006, 490, 'header', 'Spark Joy with 200-Gram Cakes!'),
(3007, 490, '_header', 'field_664b0f798280d'),
(3008, 490, 'banner_content', '<p style=\"text-align: center;\">Looking for a dazzling touch to add to your celebration? Explore our exciting selection of 200-gram cakes! These vibrant fireworks pack a punch, offering a beautiful display of color and effects at a perfect size for smaller gatherings or adding variety to a larger firework show.</p>'),
(3009, 490, '_banner_content', 'field_6655851f19ec8'),
(3010, 491, 'header', 'Reach for the Sky: Explore Our Aerial Fireworks!'),
(3011, 491, '_header', 'field_664b0f798280d'),
(3012, 491, 'banner_content', '<p style=\"text-align: center;\">Let the celebration take flight with our breathtaking selection of aerial fireworks! Experience our variety of options to paint the night sky with unforgettable bursts of color and light.</p>'),
(3013, 491, '_banner_content', 'field_6655851f19ec8'),
(3014, 492, 'header', 'High-Caliber Fun with Artillery Shells'),
(3015, 492, '_header', 'field_664b0f798280d'),
(3016, 492, 'banner_content', '<p style=\"text-align: center;\">Transform your celebration into a breathtaking spectacle with our Artillery Shells. These high-performance fireworks deliver phenomenal aerial effects, creating a dazzling display that will leave your guests in awe.</p>'),
(3017, 492, '_banner_content', 'field_6655851f19ec8'),
(3018, 493, 'header', 'Blast Off with Bottle Rockets!'),
(3019, 493, '_header', 'field_664b0f798280d'),
(3020, 493, 'banner_content', '<p style=\"text-align: center;\">Experience the classic thrill of bottle rockets! Our selection offers a variety of heights, bursts, and effects, perfect for adding a touch of nostalgic excitement and sky-high fun to any celebration. Buckle up and prepare for a soaring good time!</p>'),
(3021, 493, '_banner_content', 'field_6655851f19ec8'),
(3022, 494, 'header', 'Slice Up the Night with Cake Fireworks!'),
(3023, 494, '_header', 'field_664b0f798280d'),
(3024, 494, 'banner_content', '<p style=\"text-align: center;\">Celebrate in style with our incredible selection of cake fireworks! Offering a delightful mix of shapes, sizes, and effects, these dazzling fireworks are guaranteed to add a touch of magic and excitement to any birthday party, anniversary, or special occasion.</p>'),
(3025, 494, '_banner_content', 'field_6655851f19ec8'),
(3026, 495, 'header', 'It\'s Time for Some Fizzy Fun!'),
(3027, 495, '_header', 'field_664b0f798280d'),
(3028, 495, 'banner_content', '<p style=\"text-align: center;\">Get ready to add a sizzling soundtrack to your celebration with our epic Crackle Effects Fireworks! Fill the night with pops, crackles, and fizzes that\'ll have your guests grinning from ear to ear.</p>'),
(3029, 495, '_banner_content', 'field_6655851f19ec8'),
(3030, 496, 'header', 'Light Up Your Diwali: It\'s a Festival of Fireworks!'),
(3031, 496, '_header', 'field_664b0f798280d'),
(3032, 496, 'banner_content', '<p style=\"text-align: center;\">Celebrate Diwali with the vibrant energy it deserves! Our Diwali Fireworks Page is bursting with dazzling sparklers, colorful rockets, and everything in between. Get ready to light up the night and make your Diwali unforgettable!</p>'),
(3033, 496, '_banner_content', 'field_6655851f19ec8'),
(3034, 497, 'header', 'Take Your Celebration to New Heights!'),
(3035, 497, '_header', 'field_664b0f798280d'),
(3036, 497, 'banner_content', '<p style=\"text-align: center;\">Calling all thrill-seekers! Our Missile Page is packed with sky-rocketing missiles guaranteed to launch your celebration into another dimension. Get ready for epic bursts, dazzling trails, and a night to remember!</p>'),
(3037, 497, '_banner_content', 'field_6655851f19ec8'),
(3038, 498, 'header', 'Let the Fun Repeat on You! '),
(3039, 498, '_header', 'field_664b0f798280d'),
(3040, 498, 'banner_content', '<p style=\"text-align: center;\">Get ready for a non-stop fireworks frenzy with our Repeater Effects Fireworks! These sparklers and firecrackers are all about rapid-fire fun, keeping the party pumping and the night sky illuminated.</p>'),
(3041, 498, '_banner_content', 'field_6655851f19ec8'),
(3042, 500, 'header', ' Light Up the Fun, One Blast at a Time!'),
(3043, 500, '_header', 'field_664b0f798280d'),
(3044, 500, 'banner_content', '<p style=\"text-align: center;\">Our Single Shot Tubes are the perfect way to add pops of color and surprise to your celebration. With a variety of effects to choose from, you can create a custom light show that\'s easy to use and guaranteed to impress!</p>'),
(3045, 500, '_banner_content', 'field_6655851f19ec8'),
(3046, 501, 'header', 'Blast Off with Our Sky Rockets'),
(3047, 501, '_header', 'field_664b0f798280d'),
(3048, 501, 'banner_content', '<p style=\"text-align: center;\">Get ready to reach for the stars with our incredible selection of skyrockets! These sky-high flyers will add a touch of explosive fun to any celebration, leaving your guests in awe as they soar through the night sky with dazzling bursts of color.</p>'),
(3049, 501, '_banner_content', 'field_6655851f19ec8'),
(3050, 502, 'header', 'Get Ready to Spin Out!'),
(3051, 502, '_header', 'field_664b0f798280d'),
(3052, 502, 'banner_content', '<p style=\"text-align: center;\">Buckle up and get ready to spin with our awesome selection of spinner fireworks! These twirling beauties create a mesmerizing display of sparks and colorful flames, guaranteed to leave your guests starry-eyed (and maybe a little dizzy in the best way possible!).</p>'),
(3053, 502, '_banner_content', 'field_6655851f19ec8'),
(3054, 503, 'header', 'Let\'s Get Whistlin\': Fun & Festive Fireworks for All'),
(3055, 503, '_header', 'field_664b0f798280d'),
(3056, 503, 'banner_content', '<p style=\"text-align: center;\">Get ready to add some serious \"whoosh\" to your next celebration with our epic Whistle Fireworks. Light them up, sit back, and enjoy the symphony of whistles and dazzling bursts that will leave your guests cheering for more!</p>'),
(3057, 503, '_banner_content', 'field_6655851f19ec8'),
