(3709, 454, 'header', 'Buckle Up for Blast-Off with Snake Fireworks!'),
(3710, 454, '_header', 'field_664b0f798280d'),
(3711, 454, 'banner_content', '<p style=\"text-align: center;\">These mesmerizing pyrotechnics create a slithering column of ash, perfect for backyard celebrations or science experiments. Learn how they work, make your own (safely!), and find them for your next event. Dive into the world of black snakes today!</p>'),
(3712, 454, '_banner_content', 'field_6655851f19ec8'),
