(3719, 632, '_wp_page_template', 'default'),
(3720, 632, 'header', 'Unleash the Boom, Brighten the Room '),
(3721, 632, '_header', 'field_664b0f798280d'),
(3722, 632, 'banner_content', '<p style=\"text-align: center;\">Get ready to rock the night with our extreme fireworks. Warning: these bad boys are loud and proud, guaranteed to light up your party, and will leave everyone speechless.</p>'),
(3723, 632, '_banner_content', 'field_6655851f19ec8'),
(3724, 632, '_yoast_wpseo_primary_category', ''),
