(3731, 639, '_edit_last', '1'),
(3732, 639, '_wp_page_template', 'default'),
(3733, 639, 'header', 'Take Your Celebration to New Heights with Helicopter Fireworks'),
(3734, 639, '_header', 'field_664b0f798280d'),
(3735, 639, 'banner_content', '<p style=\"text-align: center;\">Ditch the boring fireworks display and level up your event! Imagine a dazzling shower of light raining down from above, making your party the talk of the town. Helicopter fireworks, it\'s the must-have upgrade for any celebration.</p>'),
(3736, 639, '_banner_content', 'field_6655851f19ec8'),
(3737, 639, '_yoast_wpseo_primary_category', ''),
(3738, 639, '_yoast_wpseo_estimated-reading-time-minutes', '1'),
