(3747, 640, 'header', 'Enjoy the Fun of Fireworks Without the Boom'),
(3748, 640, '_header', 'field_664b0f798280d'),
(3749, 640, 'banner_content', '<p style=\"text-align: center;\">Our low-noise fireworks let you enjoy the dazzling lights and festive atmosphere without the big boom. It\'s perfect for creating unforgettable memories that are kind to your ears and your neighbors\'.</p>'),
(3750, 640, '_banner_content', 'field_6655851f19ec8'),
(3751, 640, '_yoast_wpseo_primary_category', ''),
