(3762, 641, 'header', 'Spark Something Spectacular with these Novelty Fireworks'),
(3763, 641, '_header', 'field_664b0f798280d'),
(3764, 641, 'banner_content', '<p style=\"text-align: center;\">Our dazzling novelty fireworks go beyond the boom, adding pops of color, sizzling surprises, and laughter to your night. Get ready to Spark Something Spectacular with OC Fireworks!</p>'),
(3765, 641, '_banner_content', 'field_6655851f19ec8'),
