(3776, 642, 'header', 'Light Up the Night, Watch Colors Take Flight'),
(3777, 642, '_header', 'field_664b0f798280d'),
(3778, 642, 'banner_content', '<p style=\"text-align: center;\">Our parachute fireworks take the party to new heights. These colorful bursts unfurl slowly, raining down a shower of sparkling fun for a grand finale that\'ll leave everyone saying \"Wow!\"</p>'),
(3779, 642, '_banner_content', 'field_6655851f19ec8'),
