(3817, 645, '_wp_page_template', 'default'),
(3818, 645, 'header', 'Celebrate Safely with OC Fireworks\' Safe & Sane Collection'),
(3819, 645, '_header', 'field_664b0f798280d'),
(3820, 645, 'banner_content', '<p style=\"text-align: center;\"> Our Safe and Sane fireworks are all fun and zero fuss. Think sparklers, sizzling snakes, and colorful fountains - perfect for backyard celebrations that won\'t wake the neighbors.</p>'),
(3821, 645, '_banner_content', 'field_6655851f19ec8'),
