(3845, 647, '_wp_page_template', 'default'),
(3846, 647, 'header', 'Whiz & Bang! Unleash the Snap Attack'),
(3847, 647, '_header', 'field_664b0f798280d'),
(3848, 647, 'banner_content', '<p style=\"text-align: center;\">Crackle the fun up a notch with OC Fireworks\' Snaps! Our collection of poppers, bangers, and whiz-bangs will have you popping with laughter and keeping the party snappin\' all night long. Get ready for some finger-snappin\' good times!</p>');
