(4610, 759, '_wp_page_template', 'default'),
(4611, 759, 'header', 'Turn Nights into Spectacles with Extraordinary Fireworks'),
(4612, 759, '_header', 'field_664b0f798280d'),
(4613, 759, 'banner_content', '<p style=\"text-align: center;\">We understand the power of fireworks to turn ordinary nights into unforgettable spectacles. Our exceptional range of fireworks supplies is designed to captivate and amaze you, ensuring your celebrations are truly extraordinary.</p>'),
(4614, 759, '_banner_content', 'field_6655851f19ec8'),
