(4684, 773, 'header', 'Add Some Sizzle to your Celebration with Crackling Firecrackers'),
(4685, 773, '_header', 'field_664b0f798280d'),
(4686, 773, 'banner_content', '<p style=\"text-align: center;\">Bring the wow factor to your next celebration! Our crackling firecrackers add a layer of dazzling excitement with every pop and sizzle. Light up the night and ignite unforgettable memories with OC Fireworks.</p>'),
(4687, 773, '_banner_content', 'field_6655851f19ec8'),
(4688, 774, 'header', 'Mesmerizing Movements: Explore the Beauty of Fountains'),
(4689, 774, '_header', 'field_664b0f798280d'),
(4690, 774, 'banner_content', '<p style=\"text-align: center;\">Witness a mesmerizing dance of light and motion with our Fountain fireworks! These captivating displays erupt in a cascade of sparkling bursts, creating a breathtaking spectacle that will leave you awestruck.</p>'),
(4691, 774, '_banner_content', 'field_6655851f19ec8'),
(4692, 775, 'header', 'Ground Fireworks for Explosive Fun & Sparking Memories'),
(4693, 775, '_header', 'field_664b0f798280d'),
(4694, 775, 'banner_content', '<p style=\"text-align: center;\">Light the fuse on explosive fun with our epic selection of ground fireworks! Get ready to create memories that will spark joy long after the last sparkler fizzles out. Light it up and get ready for some serious backyard BOOM!</p>'),
(4695, 775, '_banner_content', 'field_6655851f19ec8'),
(4696, 776, 'header', 'Let’s Add Some Smoking Fun with these Smoke Items'),
(4697, 776, '_header', 'field_664b0f798280d'),
(4698, 776, 'banner_content', '<p style=\"text-align: center;\">Ditch the ordinary fireworks and ignite some smoky fun. Our selection of smoke items lets you add a mysterious touch to your celebration, perfect for creating unforgettable memories. Let\'s get hazy!</p>'),
(4699, 776, '_banner_content', 'field_6655851f19ec8'),
(4700, 777, 'header', 'Get the Excitement Rolling with Our Wheels Fireworks'),
(4701, 777, '_header', 'field_664b0f798280d'),
(4702, 777, 'banner_content', '<p style=\"text-align: center;\">Ready to set the party ablaze? Get the excitement rolling with our Wheels Fireworks! These dazzling fireworks are perfect for adding some spin (and sparkle) to your celebration.</p>'),
(4703, 777, '_banner_content', 'field_6655851f19ec8'),
(4704, 778, 'header', 'Unleash the Boom, Brighten the Room '),
(4705, 778, '_header', 'field_664b0f798280d'),
(4706, 778, 'banner_content', '<p style=\"text-align: center;\">Get ready to rock the night with our extreme fireworks. Warning: these bad boys are loud and proud, guaranteed to light up your party, and will leave everyone speechless.</p>'),
(4707, 778, '_banner_content', 'field_6655851f19ec8'),
(4708, 779, 'header', 'Take Your Celebration to New Heights with Helicopter Fireworks'),
(4709, 779, '_header', 'field_664b0f798280d'),
(4710, 779, 'banner_content', '<p style=\"text-align: center;\">Ditch the boring fireworks display and level up your event! Imagine a dazzling shower of light raining down from above, making your party the talk of the town. Helicopter fireworks, it\'s the must-have upgrade for any celebration.</p>'),
(4711, 779, '_banner_content', 'field_6655851f19ec8'),
(4712, 780, 'header', 'Enjoy the Fun of Fireworks Without the Boom'),
(4713, 780, '_header', 'field_664b0f798280d'),
(4714, 780, 'banner_content', '<p style=\"text-align: center;\">Our low-noise fireworks let you enjoy the dazzling lights and festive atmosphere without the big boom. It\'s perfect for creating unforgettable memories that are kind to your ears and your neighbors\'.</p>'),
(4715, 780, '_banner_content', 'field_6655851f19ec8'),
(4716, 781, 'header', 'Spark Something Spectacular with these Novelty Fireworks'),
(4717, 781, '_header', 'field_664b0f798280d'),
(4718, 781, 'banner_content', '<p style=\"text-align: center;\">Our dazzling novelty fireworks go beyond the boom, adding pops of color, sizzling surprises, and laughter to your night. Get ready to Spark Something Spectacular with OC Fireworks!</p>'),
(4719, 781, '_banner_content', 'field_6655851f19ec8'),
(4720, 446, '_yoast_wpseo_title', 'Firecrackers for Sale | Overstock Central Fireworks'),
(4721, 446, '_yoast_wpseo_metadesc', 'OC Fireworks offers top-quality firecrackers for sale. Shop now to add excitement to your events!'),
(4722, 448, '_yoast_wpseo_title', 'Fountain Fireworks | Overstock Central Fireworks'),
(4723, 448, '_yoast_wpseo_metadesc', 'Create beautiful ground displays with fountain fireworks from OC Fireworks - available now online!'),
(4724, 450, '_yoast_wpseo_title', 'Ground Fireworks | Overstock Central Fireworks'),
(4725, 450, '_yoast_wpseo_metadesc', 'OC Fireworks offers a diverse selection of ground fireworks. Create magical moments with their stunning effects!'),
(4726, 452, '_yoast_wpseo_title', 'Smoke Bombs Fireworks | Overstock Central Fireworks'),
(4727, 452, '_yoast_wpseo_metadesc', 'Add a splash of color to your event with smoke bombs - buy online today from OC Fireworks!'),
(4728, 454, '_yoast_wpseo_title', 'Snake Fireworks | Overstock Central Fireworks'),
(4729, 454, '_yoast_wpseo_metadesc', 'Buy snake fireworks here: small, non-exploding fireworks, ideal for adding unique ground displays to your events!'),
(4730, 456, '_yoast_wpseo_title', 'Wheel Fireworks | Overstock Central Fireworks'),
(4731, 456, '_yoast_wpseo_metadesc', 'Add exciting spins and colors to your next fireworks display with wheel fireworks for sale - shop here!'),
(4732, 632, '_yoast_wpseo_title', 'Loud Fireworks | Loudest Fireworks for Sale'),
(4733, 632, '_yoast_wpseo_metadesc', 'OC Fireworks: Your source for the loudest fireworks. Add excitement with our thunderous, attention-grabbing fireworks!'),
(4734, 639, '_yoast_wpseo_title', 'Helicopter Fireworks | Paper Lanters & Sky Flyers'),
(4735, 639, '_yoast_wpseo_metadesc', 'Helicopter fireworks, spin, fly up straight in the air, change color, and more! Buy them here - we have a variety of sizes & styles!'),
(4736, 640, '_yoast_wpseo_title', 'Low Noise Fireworks | Overstock Central Fireworks'),
(4737, 640, '_yoast_wpseo_metadesc', 'Need a quieter fireworks display? Buy low-noise fireworks from OC Fireworks! Perfect for beautiful displays with minimal sound.'),
(4738, 641, '_yoast_wpseo_title', 'Novelty Fireworks | Overstock Central Fireworks'),
(4739, 641, '_yoast_wpseo_metadesc', 'OC Fireworks offers a wide selection of novelty fireworks. Shop now for unique and entertaining effects!');
INSERT INTO `wp_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES
(4740, 642, '_yoast_wpseo_title', 'Parachute Fireworks | Overstock Central Fireworks'),
(4741, 642, '_yoast_wpseo_metadesc', 'Get your parachute fireworks online from OC Fireworks! Add them for colorful and fun aerial displays at your next event.'),
(4742, 643, '_yoast_wpseo_title', 'Plane Fireworks | Overstock Central Fireworks'),
(4743, 643, '_yoast_wpseo_metadesc', 'Get ready for a sky-high show with OC Fireworks\' plane fireworks! Explore our product range here.'),
(4744, 644, '_yoast_wpseo_title', 'Roman Candle Fireworks | Overstock Central Fireworks'),
(4745, 644, '_yoast_wpseo_metadesc', 'Light up the sky with vibrant Roman candles from OC Fireworks. Explore our selection here for classic, multi-shot displays.'),
(4746, 645, '_yoast_wpseo_title', 'Safe & Sane Fireworks | Overstock Central Fireworks'),
(4747, 645, '_yoast_wpseo_metadesc', 'OC Fireworks offers Safe and Sane fireworks - perfect for events & gatherings with an assortment of colorful fountains and ground items!'),
(4748, 646, '_yoast_wpseo_title', 'Sky Lanterns | Overstock Central Fireworks'),
(4749, 646, '_yoast_wpseo_metadesc', 'OC Fireworks: Your source for captivating sky lanterns. Buy now and fill the night sky with fun displays of floating lights!'),
(4750, 647, '_yoast_wpseo_title', 'Snaps Fireworks | Overstock Central Fireworks'),
(4751, 647, '_yoast_wpseo_metadesc', 'Enjoy the classic fun of snapping pops and crackles with a variety of snaps fireworks from OC Fireworks.'),
(4752, 657, '_yoast_wpseo_title', 'Sparkler Fireworks for Sale | Overstock Central Fireworks'),
(4753, 657, '_yoast_wpseo_metadesc', 'Browse a range of decorative sparklers for weddings, new years, and other events here at OC Fireworks!'),
(4754, 720, '_yoast_wpseo_title', 'Cheap Fireworks for Sale - 5$ or Less | Overstock Central Fireworks'),
(4755, 720, '_yoast_wpseo_metadesc', 'Shop for fireworks under $5 here. Make every celebration memorable without stretching your budget!'),
(4756, 723, '_yoast_wpseo_title', 'Firework Assortments | Overstock Central Fireworks'),
(4757, 723, '_yoast_wpseo_metadesc', 'Discover excitement in every box with OC Fireworks\' assortment boxes. Explore our mix of hand-held fireworks, fountains, and more!'),
(4758, 726, '_yoast_wpseo_title', 'Fireworks Sale - Buy 1 Get 1 Free | Overstock Central Fireworks'),
(4759, 726, '_yoast_wpseo_metadesc', 'Double the excitement with OC Fireworks\' Buy 1 Get 1 Free deals. Enjoy twice the fun with our exclusive offers!'),
(4760, 721, '_yoast_wpseo_title', 'Closeout Fireworks | Overstock Central Fireworks'),
(4761, 721, '_yoast_wpseo_metadesc', 'Closeout fireworks for sale here. Take advantage of our clearance prices and shop from our discounted selection!'),
(4762, 724, '_yoast_wpseo_title', 'Counter Boxes - Bulk Firework Packages | Overstock Central Fireworks'),
(4763, 724, '_yoast_wpseo_metadesc', 'OC Fireworks\' counter display boxes are perfect for retail stores and enthusiasts stocking up on their favorite fireworks!'),
(4764, 727, '_yoast_wpseo_title', 'Free Shipping Fireworks | Overstock Central Fireworks'),
(4765, 727, '_yoast_wpseo_metadesc', 'OC Fireworks offers free shipping on select fireworks. Shop now and enjoy the thrill of fireworks without the extra cost!'),
(4766, 722, '_yoast_wpseo_title', 'Low Cost Shipping Fireworks | Overstock Central Fireworks'),
(4767, 722, '_yoast_wpseo_metadesc', 'OC Fireworks offers low-cost shipping on fireworks, making it easier than ever to enjoy your celebrations without expensive shipping fees.'),
(4768, 725, '_yoast_wpseo_title', 'New for 2024 Fireworks | Overstock Central Fireworks'),
(4769, 725, '_yoast_wpseo_metadesc', 'Light up the sky with OC Fireworks\' newest additions for 2024. Shop our latest arrivals here.'),
(4770, 728, '_yoast_wpseo_title', 'Firework Specials | Overstock Central Fireworks'),
(4771, 728, '_yoast_wpseo_metadesc', 'Shop our exclusive deals here and enjoy savings on top-quality pyrotechnics.'),
(4772, 757, '_yoast_wpseo_title', 'Electronic Firing System for Fireworks | Overstock Central Fireworks'),
(4773, 757, '_yoast_wpseo_metadesc', 'Make your fireworks shows safer and more efficient with OC Fireworks\' electronic firing systems.'),
(4774, 759, '_yoast_wpseo_title', 'Firework Supplies | Overstock Central Fireworks'),
(4775, 759, '_yoast_wpseo_metadesc', 'OC Fireworks has all the supplies you need for a dazzling fireworks show. Shop now!'),
(4776, 760, '_yoast_wpseo_title', 'Fuses for Fireworks | Overstock Central Fireworks'),
(4777, 760, '_yoast_wpseo_metadesc', 'Get high-quality fuses used for consumer and professional fireworks here from OC Fireworks.'),
(4778, 758, '_yoast_wpseo_title', 'Tubes & Racks for Fireworks | Overstock Central Fireworks'),
(4779, 758, '_yoast_wpseo_metadesc', 'Set up your fireworks displays with confidence using OC Fireworks\' tubes and racks.'),
