(4950, 806, '_yoast_wpseo_title', 'Store Hours | Overstock Central Fireworks'),
(4951, 806, '_yoast_wpseo_metadesc', 'See OC Fireworks\' operating hours here - We welcome you to visit our retail store! Open year-round, Monday-Saturday.'),
(4952, 806, '_yoast_wpseo_estimated-reading-time-minutes', '0'),
(4953, 806, '_yoast_wpseo_wordproof_timestamp', ''),
(4954, 807, 'header', ''),
(4955, 807, '_header', 'field_664b0f798280d'),
(4956, 807, 'banner_content', ''),
(4957, 807, '_banner_content', 'field_6655851f19ec8'),
(4958, 291, '_yoast_wpseo_primary_category', ''),
(4959, 811, 'header', 'Shop Wholesale'),
(4960, 811, '_header', 'field_664b0f798280d'),
(4961, 811, 'banner_content', '<p style=\"text-align: center;\">Buying wholesale fireworks online is the savvy choice for event planners and pyro enthusiasts! At OC Fireworks, we offer a huge selection of top-quality products at discounted prices. Whether it\'s a big bash or an intimate gathering, get more bang for your buck with wholesale fireworks online!</p>\r\nWith the convenience of online shopping and the assurance of bulk discounts, our team makes it easy to stock up on fireworks for any occasion, ensuring a memorable and exhilarating experience for all.'),
(4962, 811, '_banner_content', 'field_6655851f19ec8'),
(4963, 812, '_wp_attached_file', '2024/07/Parachutes.png'),
(4964, 812, '_wp_attachment_metadata', 'a:6:{s:5:\"width\";i:1920;s:6:\"height\";i:700;s:4:\"file\";s:22:\"2024/07/Parachutes.png\";s:8:\"filesize\";i:731292;s:5:\"sizes\";a:0:{}s:10:\"image_meta\";a:12:{s:8:\"aperture\";s:1:\"0\";s:6:\"credit\";s:0:\"\";s:6:\"camera\";s:0:\"\";s:7:\"caption\";s:0:\"\";s:17:\"created_timestamp\";s:1:\"0\";s:9:\"copyright\";s:0:\"\";s:12:\"focal_length\";s:1:\"0\";s:3:\"iso\";s:1:\"0\";s:13:\"shutter_speed\";s:1:\"0\";s:5:\"title\";s:0:\"\";s:11:\"orientation\";s:1:\"0\";s:8:\"keywords\";a:0:{}}}'),
(4965, 642, '_thumbnail_id', '812'),
(4966, 813, 'header', 'Buckle Up for Blast-Off with Snake Fireworks!'),
(4967, 813, '_header', 'field_664b0f798280d'),
(4968, 813, 'banner_content', '<p style=\"text-align: center;\">These mesmerizing pyrotechnics create a slithering column of ash, perfect for backyard celebrations or science experiments. Learn how they work, make your own (safely!), and find them for your next event. Dive into the world of black snakes today!</p>'),
(4969, 813, '_banner_content', 'field_6655851f19ec8'),
(4970, 814, 'header', 'Turn Nights into Spectacles with Extraordinary Fireworks'),
(4971, 814, '_header', 'field_664b0f798280d'),
(4972, 814, 'banner_content', '<p style=\"text-align: center;\">We understand the power of fireworks to turn ordinary nights into unforgettable spectacles. Our exceptional range of fireworks supplies is designed to captivate and amaze you, ensuring your celebrations are truly extraordinary.</p>'),
(4973, 814, '_banner_content', 'field_6655851f19ec8');
